function clamp(t,r,e){return Math.min(Math.max(t,r),e)}function squaredSegmentDistance(t,r,e,n,o,a){var u,i=o-e,c=a-n;return 0==i&&0==c||(1<(u=((t-e)*i+(r-n)*c)/(i*i+c*c))?(e=o,n=a):0<u&&(e+=i*u,n+=c*u)),squaredDistance(t,r,e,n)}function squaredDistance(t,r,e,n){e-=t,t=n-r;return e*e+t*t}function solveLinearSystem(o){var a=o.length;for(let n=0;n<a;n++){let r=n,e=Math.abs(o[n][n]);for(let t=n+1;t<a;t++){var u=Math.abs(o[t][n]);u>e&&(e=u,r=t)}if(0===e)return null;var t=o[r];o[r]=o[n],o[n]=t;for(let r=n+1;r<a;r++){var i=-o[r][n]/o[n][n];for(let t=n;t<a+1;t++)n==t?o[r][t]=0:o[r][t]+=i*o[n][t]}}const e=new Array(a);for(let r=a-1;0<=r;r--){e[r]=o[r][a]/o[r][r];for(let t=r-1;0<=t;t--)o[t][a]-=o[t][r]*e[r]}return e}function toDegrees(t){return 180*t/Math.PI}function toRadians(t){return t*Math.PI/180}function modulo(t,r){t%=r;return t*r<0?t+r:t}function lerp(t,r,e){return t+e*(r-t)}function toFixed(t,r){r=Math.pow(10,r);return Math.round(t*r)/r}function round(t,r){return Math.round(toFixed(t,r))}function floor(t,r){return Math.floor(toFixed(t,r))}function ceil(t,r){return Math.ceil(toFixed(t,r))}function wrap(t,r,e){if(r<=t&&t<e)return t;e-=r;return((t-r)%e+e)%e+r}export{clamp,squaredSegmentDistance,squaredDistance,solveLinearSystem,toDegrees,toRadians,modulo,lerp,toFixed,round,floor,ceil,wrap};